class XPConfigManager:
    """小鹏AI编码治理配置管理器"""

    def __init__(self, config_dir: str = "config"):
        self.config_dir = Path(config_dir)
        self.config_dir.mkdir(exist_ok=True)

        self.main_config_file = self.config_dir / "xp_ai_coding_config.yaml"
        self.backup_dir = self.config_dir / "backups"
        self.backup_dir.mkdir(exist_ok=True)

        self._config: Optional[XPAICodingConfig] = None

    def load_config(self, config_file: Optional[str] = None) -> XPAICodingConfig:
        """加载配置文件"""
        config_path = Path(config_file) if config_file else self.main_config_file

        if config_path.exists():
            try:
                with open(config_path, 'r', encoding='utf-8') as f:
                    data = yaml.safe_load(f)

                # 将字典转换为XPAICodingConfig对象
                self._config = self._dict_to_config(data)
                return self._config

            except Exception as e:
                print(f"Warning: Failed to load config from {config_path}: {e}")
                print("Using default configuration...")

        # 使用默认配置
        self._config = XPAICodingConfig()
        return self._config

    def save_config(self, config: Optional[XPAICodingConfig] = None,
                   backup: bool = True) -> bool:
        """保存配置文件"""
        if config is None:
            config = self._config

        if config is None:
            return False

        try:
            # 备份现有配置
            if backup and self.main_config_file.exists():
                self._create_backup()

            # 保存配置
            config_dict = asdict(config)
            with open(self.main_config_file, 'w', encoding='utf-8') as f:
                yaml.dump(config_dict, f, default_flow_style=False,
                         allow_unicode=True, sort_keys=False)

            return True

        except Exception as e:
            print(f"Error: Failed to save config: {e}")
            return False

    def validate_config(self, config: Optional[XPAICodingConfig] = None) -> Dict[str, List[str]]:
        """验证配置完整性和有效性"""
        if config is None:
            config = self._config

        if config is None:
            return {"error": ["No configuration to validate"]}

        validation_errors = {}

        # 验证基本信息
        if not config.project_name:
            validation_errors.setdefault("project", []).append("Project name is required")

        # 验证权限配置
        permission_errors = self._validate_permissions(config.permission_config)
        if permission_errors:
            validation_errors["permissions"] = permission_errors

        # 验证标准配置
        standards_errors = self._validate_standards(config.standards_config)
        if standards_errors:
            validation_errors["standards"] = standards_errors

        # 验证AI配置
        ai_errors = self._validate_ai_config(config.ai_assist_config)
        if ai_errors:
            validation_errors["ai_assist"] = ai_errors

        return validation_errors

    def _validate_permissions(self, permission_config: Dict[str, Any]) -> List[str]:
        """验证权限配置"""
        errors = []

        if not permission_config.get("roles"):
            errors.append("No roles defined")

        if not permission_config.get("module_permissions"):
            errors.append("No module permissions defined")

        # 验证角色权限的一致性
        roles = permission_config.get("roles", {})
        module_permissions = permission_config.get("module_permissions", {})

        for module_name, module_config in module_permissions.items():
            for role_type in ["read_roles", "write_roles", "ai_assist_roles"]:
                role_list = module_config.get(role_type, [])
                if "*" not in role_list:  # 跳过通配符
                    for role in role_list:
                        if role not in roles:
                            errors.append(f"Role '{role}' referenced in {module_name}.{role_type} not defined")

        return errors

    def _validate_standards(self, standards_config: Dict[str, Any]) -> List[str]:
        """验证标准配置"""
        errors = []

        if not standards_config.get("enabled_rule_categories"):
            errors.append("No rule categories enabled")

        rule_sets = standards_config.get("rule_sets", {})
        if not rule_sets:
            errors.append("No rule sets defined")

        return errors

    def _validate_ai_config(self, ai_config: Dict[str, Any]) -> List[str]:
        """验证AI配置"""
        errors = []

        if not ai_config.get("enabled"):
            return errors  # AI未启用，跳过验证

        if not ai_config.get("suggestion_types"):
            errors.append("No suggestion types defined")

        if not ai_config.get("module_specific_guidance"):
            errors.append("No module-specific guidance defined")

        return errors

    def _create_backup(self):
        """创建配置备份"""
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_file = self.backup_dir / f"xp_ai_coding_config_{timestamp}.yaml"

        try:
            import shutil
            shutil.copy2(self.main_config_file, backup_file)
        except Exception as e:
            print(f"Warning: Failed to create backup: {e}")

    def _dict_to_config(self, data: Dict[str, Any]) -> XPAICodingConfig:
        """将字典转换为配置对象"""
        return XPAICodingConfig(
            version=data.get("version", "1.0.0"),
            project_name=data.get("project_name", "XPMotors_iOS"),
            team_name=data.get("team_name", "小鹏汽车iOS团队"),
            created_at=data.get("created_at", ""),
            updated_at=data.get("updated_at", ""),
            project_settings=data.get("project_settings"),
            permission_config=data.get("permission_config"),
            standards_config=data.get("standards_config"),
            ai_assist_config=data.get("ai_assist_config"),
            integration_config=data.get("integration_config")
        )

    def export_config(self, format: str = "yaml", output_file: Optional[str] = None) -> str:
        """导出配置为指定格式"""
        if self._config is None:
            raise ValueError("No configuration loaded")

        config_dict = asdict(self._config)

        if format.lower() == "json":
            content = json.dumps(config_dict, ensure_ascii=False, indent=2)
            extension = "json"
        elif format.lower() == "yaml":
            content = yaml.dump(config_dict, default_flow_style=False,
                              allow_unicode=True, sort_keys=False)
            extension = "yaml"
        else:
            raise ValueError(f"Unsupported format: {format}")

        if output_file:
            output_path = Path(output_file)
        else:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            output_path = self.config_dir / f"export_config_{timestamp}.{extension}"

        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(content)

        return str(output_path)

    def get_current_config(self) -> Optional[XPAICodingConfig]:
        """获取当前配置"""
        return self._config

    def update_config_section(self, section: str, updates: Dict[str, Any]) -> bool:
        """更新配置的特定部分"""
        if self._config is None:
            return False

        try:
            if section == "project_settings":
                self._config.project_settings.update(updates)
            elif section == "permission_config":
                self._config.permission_config.update(updates)
            elif section == "standards_config":
                self._config.standards_config.update(updates)
            elif section == "ai_assist_config":
                self._config.ai_assist_config.update(updates)
            elif section == "integration_config":
                self._config.integration_config.update(updates)
            else:
                return False

            self._config.updated_at = datetime.now().isoformat()
            return True

        except Exception:
            return False

# 配置管理器单例
_config_manager = None

def get_config_manager(config_dir: str = "config") -> XPConfigManager:
    """获取配置管理器单例"""
    global _config_manager
    if _config_manager is None:
        _config_manager = XPConfigManager(config_dir)
    return _config_manager

